parameters.jsCode:
const tasks = [];

for (const item of $input.all()) {
  if (item.json.title && typeof item.json.title === "string") {
    tasks.push(item.json.title.trim());
  }
}

const uniqueTasks = [...new Set(tasks)];

return [
  {
    json: {
      title: uniqueTasks.join(", ")
    }
  }
];

const items = [];

for (const item of $input.all()) {

  let text =
    item.json.schedule ||
    item.json.choices?.[0]?.message?.content ||
    "";

  // 🔥 BUANG ```json ``` kalau ada
  text = text.replace(/```json/g, "").replace(/```/g, "").trim();

  let parsed = [];

  try {
    parsed = JSON.parse(text);
  } catch (e) {
    console.log("Parse error:", text);
    parsed = [];
  }

  for (const t of parsed) {
    if (t.task && t.time) {
      items.push({
        json: {
          task: t.task,
          time: t.time,
          source: "ai"
        }
      });
    }
  }
}

return items;

const text = $json.message || '';
const chatId = $json.chat_id || 'YOUR_TELEGRAM_CHAT_ID';
const source = $json.source || 'web_app';

return {
  json: {
    task: text,
    source: source,
    chat_id: chatId,
    user_text: text.trim(),
    timestamp: new Date().toISOString()
  }
};

