const items = [];

for (const item of $input.all()) {
  let text = item.json.choices?.[0]?.message?.content || "[]";

  // Clean markdown code blocks
  text = text.replace(/```json/g, '').replace(/```/g, '').trim();

  let parsed = [];
  try {
    parsed = JSON.parse(text);
  } catch (e) {
    console.log("Parse error:", text);
    parsed = [];
  }

  for (const t of parsed) {
    if (t.task && t.time) {
      items.push({
        json: {
          task: t.task,
          time: t.time,
          date: t.date || new Date().toISOString().split('T')[0],
          source: "ai",
          chat_id: "YOUR_TELEGRAM_CHAT_ID",
          status: "pending"
        }
      });
    }
  }
}

return items;

const inserted = $input.all();
const chatId = 'YOUR_TELEGRAM_CHAT_ID';

let reply = '✅ Jadwal berhasil ditambahkan!\n\n';

inserted.forEach((item, idx) => {
  reply += `${idx + 1}. ⏰ ${item.json.time} - ${item.json.task}\n`;
});

reply += '\nTotal: ' + inserted.length + ' tugas';

return [{
  json: {
    chat_id: chatId,
    reply: reply,
    tasks_added: inserted.length
  }
}];

const global = $getWorkflowStaticData('global');
const chatId = 'YOUR_TELEGRAM_CHAT_ID';
const text = $json.user_text || '';

// Initialize jika belum ada
if (!global[chatId]) {
  global[chatId] = { mode: 'menu', conversation: [] };
}

let currentMode = global[chatId].mode || 'menu';

// LOGIKA PENTING: Jika command /ngobrol, set mode chat
if (text === '/ngobrol') {
  currentMode = 'chat';
  global[chatId].mode = 'chat';
  global[chatId].conversation = []; // Reset conversation

  return [{
    json: {
      chat_id: chatId,
      user_text: 'Halo! 👋 Saya AI Productivity Assistant kamu. Ada yang bisa saya bantu?',
      mode: 'chat',
      is_ngobrol_command: true, // Flag khusus
      conversation_history: [],
      message: $json.message
    }
  }];
} 
else if (text === '/cancel' || text === '/start') {
  currentMode = 'menu';
  global[chatId].mode = 'menu';
  global[chatId].conversation = [];
} 
else if (currentMode === 'chat') {
  // Jika sudah dalam mode chat, simpan pesan user
  if (!global[chatId].conversation) {
    global[chatId].conversation = [];
  }

  global[chatId].conversation.push({
    role: 'user',
    content: text,
    timestamp: new Date().toISOString()
  });

  // Batasi 10 pesan terakhir
  if (global[chatId].conversation.length > 10) {
    global[chatId].conversation = global[chatId].conversation.slice(-10);
  }
}

return [{
  json: {
    chat_id: chatId,
    user_text: text,
    mode: currentMode,
    conversation_history: global[chatId].conversation,
    message: $json.message
  }
}];

const text = $json.message?.text || $json.message?.caption || $json.edited_message?.text || 'no text';
const chatId = String($json.message?.chat?.id || 'YOUR_TELEGRAM_CHAT_ID');

if (!chatId || chatId === 'null') {
  throw new Error('Chat ID Missing');
}

return {
  json: {
    task: text,
    source: 'telegram',
    chat_id: chatId,
    message: $json.message,
    user_text: text.trim(),
    timestamp: new Date().toISOString()
  }
};

const schedules = $input.all().map(item => item.json);
const chatId = 'YOUR_TELEGRAM_CHAT_ID';
const today = new Date().toISOString().split('T')[0];

const filtered = schedules.filter(item => 
  item.chat_id === chatId || item.chat_id === null || !item.chat_id
);

filtered.sort((a, b) => {
  const dateA = a.date ? new Date(`${a.date}T${a.time || '00:00'}`) : new Date('9999-12-31');
  const dateB = b.date ? new Date(`${b.date}T${b.time || '00:00'}`) : new Date('9999-12-31');
  return dateA - dateB;
});

if (!filtered || filtered.length === 0) {
  return [{
    json: {
      chat_id: chatId,
      reply: '📅 **Jadwal Kosong Hari Ini**\n\nBelum ada jadwal untuk ' + today + '.\n\nGunakan /buat untuk menambah jadwal baru.'
    }
  }];
}

let reply = '📅 **Jadwal Hari Ini** (' + today + ')\n━━━━━━━━━━━━━━\n\n';

filtered.forEach((item, index) => {
  const icon = item.status === 'done' ? '✅' : '⏳';
  const statusText = item.status === 'done' ? '[SELESAI]' : '[BELUM]';
  const taskId = item.id;

  reply += `${icon} **ID: ${taskId}**\n   ⏰ ${item.time} - ${item.task}\n   _${statusText} (Ketik /done ${taskId})_\n\n`;
});

reply += '\n💡 **Total:** ' + filtered.length + ' tugas\n💡 **Cara update:** Ketik `/done [task_id]` untuk tandai selesai\n\n📌 **Contoh:** `/done ' + (filtered[0]?.id || '1') + '`';

return [{
  json: {
    chat_id: chatId,
    reply: reply,
    schedule_count: filtered.length
  }
}];

const global = $getWorkflowStaticData('global');
const chatId = $json.chat_id || 'YOUR_TELEGRAM_CHAT_ID';

// Set mode ke 'waiting_edit_input'
global[chatId] = global[chatId] || {};
global[chatId].mode = 'waiting_edit_input';
global[chatId].lastAction = new Date().toISOString();

console.log('✅ Mode edit aktif untuk chatId:', chatId);

return [{
  json: {
    chat_id: chatId,
    mode: 'waiting_edit_input',
    message: 'Mode edit aktif - menunggu input user'
  }
}];

const message = $json.message?.text || '';
const chatId = $json.message?.chat?.id;

// Parse /done 2350
const match = message.match(/\/done\s+(\d+)/);

if (!match) {
  return [{
    json: {
      chat_id: chatId,
      error: true,
      reply: 'Format salah! Gunakan: `/done [task_id]`\nContoh: `/done 2350`'
    }
  }];
}

const taskId = match[1];

return [{
  json: {
    chat_id: chatId,
    task_id: taskId,
    error: false
  }
}];

