const text = $json.user_text || $json.text || '';
const chatId = 'YOUR_TELEGRAM_CHAT_ID';

// Format: task_id | tanggal | jam | kegiatan
if (!text || !text.includes('|')) {
  return [{
    json: {
      chat_id: chatId,
      error: true,
      reply: '❌ Format salah!\n\nGunakan:\n`task_id | tanggal | jam | kegiatan`\n\nContoh:\n`2367 | 2026-04-21 | 10:00 | Rapat baru`\n\nKetik /jadwal untuk lihat task_id'
    }
  }];
}

const parts = text.split('|').map(p => p.trim());

if (parts.length !== 4) {
  return [{
    json: {
      chat_id: chatId,
      error: true,
      reply: '❌ Format tidak lengkap!\n\nHarus 4 bagian: `task_id | tanggal | jam | kegiatan`'
    }
  }];
}

const [taskIdStr, dateInput, time, task] = parts;

// Validate task_id
const taskId = parseInt(taskIdStr);
if (isNaN(taskId) || taskId <= 0) {
  return [{
    json: {
      chat_id: chatId,
      error: true,
      reply: '❌ Task ID tidak valid!\n\nTask ID harus angka positif.\nKetik /jadwal untuk lihat daftar task_id'
    }
  }];
}

// Resolve tanggal (support "besok", "hari ini", dll)
const todayObj = new Date();
todayObj.setHours(0, 0, 0, 0);

let resolvedDate;
const d = dateInput.toLowerCase().trim();

if (d === 'hari ini' || d === 'today') {
  resolvedDate = new Date(todayObj);
} else if (d === 'besok' || d === 'tomorrow') {
  resolvedDate = new Date(todayObj);
  resolvedDate.setDate(todayObj.getDate() + 1);
} else if (d === 'lusa') {
  resolvedDate = new Date(todayObj);
  resolvedDate.setDate(todayObj.getDate() + 2);
} else {
  resolvedDate = new Date(dateInput);
  if (isNaN(resolvedDate.getTime())) {
    return [{
      json: {
        chat_id: chatId,
        error: true,
        reply: '❌ Format tanggal tidak valid!\n\nGunakan: `YYYY-MM-DD` atau kata `besok`/`hari ini`'
      }
    }];
  }
}

const yyyy = resolvedDate.getFullYear();
const mm = String(resolvedDate.getMonth() + 1).padStart(2, '0');
const dd = String(resolvedDate.getDate()).padStart(2, '0');
const finalDate = `${yyyy}-${mm}-${dd}`;

// Validate time
const timeRegex = /^\d{2}:\d{2}$/;
if (!timeRegex.test(time)) {
  return [{
    json: {
      chat_id: chatId,
      error: true,
      reply: '❌ Format jam tidak valid!\n\nGunakan format: `HH:MM`\nContoh: `14:00`'
    }
  }];
}

return [{
  json: {
    chat_id: chatId,
    task_id: taskId,
    new_date: finalDate,
    new_time: time,
    new_task: task,
    error: false
  }
}];

// Ambil SEMUA data dari input (gabungan dari node sebelumnya)
const input = $input.first().json;

// Karena kamu cuma punya 1 jalur, kita anggap:
const oldData = input;       // dari HTTP Request
const parseResult = input;   // dari Code sebelumnya (yang parse)

// Kalau data lama tidak ditemukan
if (!oldData || !oldData.id) {
  return [{
    json: {
      chat_id: 'YOUR_TELEGRAM_CHAT_ID',
      error: true,
      reply: '❌ Task ID ' + (parseResult.task_id || '?') + ' tidak ditemukan!\n\nKetik /jadwal untuk lihat daftar task yang ada.'
    }
  }];
}

return [{
  json: {
    chat_id: 'YOUR_TELEGRAM_CHAT_ID',
    task_id: oldData.id,
    old_date: oldData.date || 'N/A',
    old_time: oldData.time || 'N/A',
